const body = $json.body || $json || {};

function clean(value, fallback = '') {
  return String(value ?? fallback)
    .replace(/[\u0000-\u001f\u007f]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function escapeHtml(value) {
  return clean(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function row(label, value) {
  return `<tr>
    <td style="width: 185px; padding: 10px 12px; border: 1px solid #dfe8e3; background: #f6faf8; font-weight: 700; color: #0b3d3b;">${escapeHtml(label)}</td>
    <td style="padding: 10px 12px; border: 1px solid #dfe8e3; color: #102424;">${escapeHtml(value || '-')}</td>
  </tr>`;
}

function scoreBand(score) {
  if (score >= 70) return 'Hot lead';
  if (score >= 45) return 'Qualified lead';
  return 'Needs follow-up';
}

const lead = {
  submittedAt: new Date().toISOString(),
  name: clean(body.name),
  email: clean(body.email),
  phone: clean(body.phone),
  company: clean(body.company),
  employeeCount: clean(body.employeeCount),
  interest: clean(body.interest),
  challenge: clean(body.challenge),
  leadMagnet: clean(body.leadMagnet),
  source: clean(body.source, 'LEA NACE workplace learning website'),
  pageUrl: clean(body.pageUrl),
  userAgent: clean(body.userAgent)
};

const missing = [];
for (const field of ['name', 'email', 'company', 'challenge']) {
  if (!lead[field]) missing.push(field);
}

lead.valid = missing.length === 0;
lead.missingFields = missing;
lead.leadScore = 0;
if (lead.email.includes('@') && !/(gmail|yahoo|hotmail|outlook)\./i.test(lead.email)) lead.leadScore += 15;
if (lead.company) lead.leadScore += 20;
if (lead.employeeCount) lead.leadScore += 15;
if (/AI|NACE|LEA|job redesign|productivity|grant|automation|digital/i.test(lead.interest + ' ' + lead.challenge)) lead.leadScore += 30;
if (lead.leadMagnet) lead.leadScore += 10;

lead.leadStatus = scoreBand(lead.leadScore);
lead.whatsAppUrl = lead.phone ? `https://wa.me/${lead.phone.replace(/\D/g, '')}` : '';
lead.subject = `Workplace Learning Enquiry: ${lead.company || lead.name || 'New Lead'}`;
lead.replyTo = lead.email;
lead.summary = [
  `Name: ${lead.name || '-'}`,
  `Email: ${lead.email || '-'}`,
  `Phone: ${lead.phone || '-'}`,
  `Company: ${lead.company || '-'}`,
  `Employee count: ${lead.employeeCount || '-'}`,
  `Interest: ${lead.interest || '-'}`,
  `Lead magnet: ${lead.leadMagnet || '-'}`,
  `Lead score: ${lead.leadScore} (${lead.leadStatus})`,
  '',
  'Challenge:',
  lead.challenge || '-'
].join('\n');

const nextSteps = [
  'Reply within 1 business day.',
  'Confirm business challenge, target job roles, and project champion.',
  'Check LEA/NACE fit, company size, and grant documentation readiness.',
  lead.leadMagnet ? 'Send the Workplace Learning Grant-Fit Checklist.' : 'Offer the Workplace Learning Grant-Fit Checklist if relevant.'
];

lead.emailHtml = `<div style="font-family: Arial, Helvetica, sans-serif; max-width: 720px; color: #102424; line-height: 1.55;">
  <div style="background: #0b3d3b; color: #ffffff; padding: 22px 24px; border-radius: 8px 8px 0 0;">
    <p style="margin: 0 0 6px; color: #d99a29; font-size: 12px; font-weight: 800; text-transform: uppercase;">LEA / NACE Workplace Learning Lead</p>
    <h2 style="margin: 0; font-size: 24px; line-height: 1.2;">${escapeHtml(lead.company || 'New workplace learning enquiry')}</h2>
    <p style="margin: 10px 0 0; color: #dcebe6;">${escapeHtml(lead.leadStatus)} • Score ${lead.leadScore}/90</p>
  </div>

  <table cellpadding="0" cellspacing="0" style="border-collapse: collapse; width: 100%; border: 1px solid #dfe8e3; border-top: 0;">
    ${row('Submitted', lead.submittedAt)}
    ${row('Name', lead.name)}
    ${row('Email', lead.email)}
    ${row('Phone / WhatsApp', lead.phone)}
    ${row('Company', lead.company)}
    ${row('Employee Count', lead.employeeCount)}
    ${row('Main Interest', lead.interest)}
    ${row('Lead Magnet', lead.leadMagnet)}
    ${row('Source', lead.source)}
  </table>

  <div style="padding: 20px 24px; border: 1px solid #dfe8e3; border-top: 0; background: #ffffff;">
    <h3 style="margin: 0 0 10px; color: #0b3d3b;">Project Challenge</h3>
    <p style="margin: 0; white-space: pre-wrap;">${escapeHtml(lead.challenge || '-')}</p>
  </div>

  <div style="padding: 20px 24px; border: 1px solid #dfe8e3; border-top: 0; background: #f6faf8;">
    <h3 style="margin: 0 0 10px; color: #0b3d3b;">Suggested Follow-Up</h3>
    <ol style="margin: 0; padding-left: 20px;">
      ${nextSteps.map((step) => `<li style="margin: 6px 0;">${escapeHtml(step)}</li>`).join('')}
    </ol>
  </div>

  <div style="padding: 16px 24px; border: 1px solid #dfe8e3; border-top: 0; border-radius: 0 0 8px 8px; background: #ffffff; color: #5d6d6b; font-size: 13px;">
    <p style="margin: 0 0 6px;">Page URL: ${escapeHtml(lead.pageUrl || '-')}</p>
    <p style="margin: 0;">User agent: ${escapeHtml(lead.userAgent || '-')}</p>
  </div>
</div>`;

return [{ json: lead }];
